import type { JSONSupport } from "../../../core/JSONSupport.js";

/** @since 5.0 */
export interface ColorModulationProperties extends Partial<Pick<ColorModulation, "field" | "maxValue" | "minValue">> {}

/** @since 5.0 */
export default class ColorModulation extends JSONSupport {
  constructor(properties?: ColorModulationProperties);
  /**
   * {string} Field to use for the color modulation. Commonly modulation
   *                          is used with the `intensity` field.
   *
   * @since 5.0
   */
  accessor field: string;
  /**
   * Field value at which the point color will be left unchanged.
   *
   * @default 255
   * @since 5.0
   */
  accessor maxValue: number;
  /**
   * Field value at which the point color becomes darkest.
   *
   * @default 0
   * @since 5.0
   */
  accessor minValue: number;
}